const Redis = require('ioredis');
const { randomUUID } = require('crypto');

const body = $input.first().json.body ?? {};
const patientId = $input.first().json.query?.patientId || body.patientId;
const { r2Key, filename } = body;

if (!patientId || !r2Key || !filename) {
  return [{ json: { success: false, error: 'patientId, r2Key, and filename are required' } }];
}

const redis = new Redis({ host: 'redis', port: 6379 });

try {
  const exists = await redis.exists(`patient:${patientId}`);
  if (!exists) {
    await redis.quit();
    return [{ json: { success: false, error: 'Patient not found' } }];
  }

  const photoId = randomUUID();
  const uploadedAt = new Date().toISOString();
  const url = `${process.env.R2_PUBLIC_URL}/${r2Key}`;
  const order = await redis.llen(`patient:${patientId}:photos`);

  await redis.hset(`photo:${photoId}`, {
    patientId,
    url,
    filename,
    r2Key,
    uploadedAt,
    order: String(order)
  });
  await redis.rpush(`patient:${patientId}:photos`, photoId);

  await redis.quit();
  return [{ json: { photoId, url, filename, uploadedAt, order } }];
} catch (err) {
  await redis.quit().catch(() => {});
  throw err;
}
